// Parse and validate input request
const input = $input.first().json;

// Script content (required)
const script = input.script || input.text;
if (!script) {
  throw new Error('Script/text content is required');
}

// HeyGen avatar settings
const avatarId = input.avatar_id || 'Kristin_pubblic_2_20240108';
const voiceId = input.voice_id || '1bd001e7e50f421d891986aad5158bc8';

// Video settings
const width = input.width || 1920;
const height = input.height || 1080;

// Branding settings
const branding = input.branding || {};
const logoUrl = branding.logo_url || null;
const primaryColor = branding.primary_color || '#ffffff';
const secondaryColor = branding.secondary_color || '#000000';
const fontFamily = branding.font || 'Montserrat';

// Overlay preferences
const overlayStyle = input.overlay_style || 'professional';
const autoCaptions = input.auto_captions !== false;
const autoKeyPoints = input.auto_key_points !== false;
const showLowerThird = input.show_lower_third !== false;
const speakerName = input.speaker_name || null;
const speakerTitle = input.speaker_title || null;

// Processing service (cloudinary or shotstack)
const processingService = input.processing_service || 'cloudinary';

return {
  json: {
    script,
    avatarId,
    voiceId,
    width,
    height,
    branding: {
      logoUrl,
      primaryColor,
      secondaryColor,
      fontFamily
    },
    overlayStyle,
    autoCaptions,
    autoKeyPoints,
    showLowerThird,
    speakerName,
    speakerTitle,
    processingService
  }
};

// Analyze script content and generate smart overlays
const input = $input.first().json;
const script = input.script;
const style = input.overlayStyle;
const branding = input.branding;

// Helper function to estimate word timing (avg 150 words per minute)
function estimateWordTiming(text, startOffset = 0) {
  const words = text.split(/\s+/);
  const wordsPerSecond = 2.5; // 150 wpm
  const duration = words.length / wordsPerSecond;
  return {
    start: startOffset,
    end: startOffset + duration,
    duration
  };
}

// Analyze script for key content
const sentences = script.split(/[.!?]+/).filter(s => s.trim());
const totalTiming = estimateWordTiming(script);
const videoDuration = totalTiming.duration;

const overlays = [];

// 1. Add logo watermark if provided
if (branding.logoUrl) {
  overlays.push({
    type: 'image',
    id: 'logo-watermark',
    src: branding.logoUrl,
    position: 'north_east',
    xOffset: 30,
    yOffset: 30,
    width: 150,
    opacity: 80,
    startTime: 0,
    endTime: videoDuration
  });
}

// 2. Add lower third for speaker intro
if (input.showLowerThird && (input.speakerName || input.speakerTitle)) {
  const lowerThirdText = input.speakerName 
    ? (input.speakerTitle ? `${input.speakerName}\n${input.speakerTitle}` : input.speakerName)
    : input.speakerTitle;

  overlays.push({
    type: 'lowerThird',
    id: 'speaker-intro',
    text: lowerThirdText,
    position: 'south_west',
    color: branding.primaryColor,
    backgroundColor: branding.secondaryColor,
    startTime: 1,
    endTime: 6,
    animation: 'slideIn'
  });
}

// 3. Extract and create key point overlays
if (input.autoKeyPoints) {
  // Look for patterns that indicate key points
  const keyPointPatterns = [
    /(?:first|1st|one)[,:]?\s+(.{10,80})/gi,
    /(?:second|2nd|two)[,:]?\s+(.{10,80})/gi,
    /(?:third|3rd|three)[,:]?\s+(.{10,80})/gi,
    /(?:important|key|main|crucial)[:]?\s+(.{10,80})/gi,
    /(?:remember|note)[:]?\s+(.{10,80})/gi
  ];

  let keyPointIndex = 0;
  let currentTime = 3; // Start after intro

  for (const pattern of keyPointPatterns) {
    const matches = script.matchAll(pattern);
    for (const match of matches) {
      if (keyPointIndex < 5) { // Limit to 5 key points
        const keyPoint = match[1].trim();
        const pointNumber = keyPointIndex + 1;

        // Find approximate timing for this text
        const textBefore = script.substring(0, match.index);
        const timing = estimateWordTiming(textBefore);

        overlays.push({
          type: 'text',
          id: `key-point-${pointNumber}`,
          text: `${pointNumber}. ${keyPoint.substring(0, 50)}${keyPoint.length > 50 ? '...' : ''}`,
          position: 'west',
          xOffset: 50,
          yOffset: 0,
          fontSize: style === 'bold' ? 56 : 42,
          color: branding.primaryColor,
          fontFamily: branding.fontFamily,
          startTime: Math.max(timing.end, currentTime),
          endTime: Math.min(timing.end + 5, videoDuration - 1),
          animation: 'fadeIn'
        });

        currentTime = timing.end + 6;
        keyPointIndex++;
      }
    }
  }

  // If no explicit key points found, extract from sentence structure
  if (keyPointIndex === 0 && sentences.length > 2) {
    // Use important-sounding sentences
    const importantSentences = sentences.filter(s => 
      s.length > 30 && s.length < 100 &&
      !s.toLowerCase().includes('hello') &&
      !s.toLowerCase().includes('thank')
    ).slice(0, 3);

    let sentenceTime = 5;
    importantSentences.forEach((sentence, idx) => {
      overlays.push({
        type: 'text',
        id: `highlight-${idx + 1}`,
        text: sentence.trim().substring(0, 60) + (sentence.length > 60 ? '...' : ''),
        position: 'south',
        xOffset: 0,
        yOffset: 100,
        fontSize: style === 'bold' ? 48 : 36,
        color: branding.primaryColor,
        backgroundColor: 'rgba(0,0,0,0.7)',
        fontFamily: branding.fontFamily,
        startTime: sentenceTime,
        endTime: sentenceTime + 4,
        animation: 'fadeIn'
      });
      sentenceTime += (videoDuration - 10) / importantSentences.length;
    });
  }
}

// 4. Add call-to-action if detected
const ctaPatterns = [
  /(?:visit|go to|check out)\s+(\S+\.\S+)/gi,
  /(?:call|contact)\s+(?:us at)?\s*([\d-]+)/gi,
  /(?:subscribe|follow|like)/gi,
  /(?:click|tap)\s+(?:the)?\s*(?:link|button)/gi
];

for (const pattern of ctaPatterns) {
  if (pattern.test(script)) {
    overlays.push({
      type: 'text',
      id: 'cta-overlay',
      text: '👆 Link in description',
      position: 'south',
      xOffset: 0,
      yOffset: 50,
      fontSize: 36,
      color: '#ffffff',
      backgroundColor: branding.primaryColor,
      startTime: videoDuration - 5,
      endTime: videoDuration,
      animation: 'pulse'
    });
    break;
  }
}

// 5. Apply style-specific adjustments
if (style === 'minimal') {
  // Reduce number of overlays for minimal style
  const essentialTypes = ['logo-watermark', 'speaker-intro', 'cta-overlay'];
  overlays.forEach(o => {
    if (!essentialTypes.includes(o.id)) {
      o.opacity = (o.opacity || 100) * 0.7;
    }
  });
} else if (style === 'bold') {
  // Increase visibility for bold style
  overlays.forEach(o => {
    if (o.fontSize) o.fontSize *= 1.2;
    o.fontWeight = 'bold';
  });
}

return {
  json: {
    ...input,
    generatedOverlays: overlays,
    estimatedDuration: videoDuration,
    overlayCount: overlays.length
  }
};

const response = $input.first().json;
const previousData = $('Analyze Content & Generate Overlays').first().json;

if (response.error) {
  throw new Error(`HeyGen API Error: ${response.error.message || JSON.stringify(response.error)}`);
}

const videoId = response.data?.video_id;
if (!videoId) {
  throw new Error('No video_id returned from HeyGen API');
}

return {
  json: {
    videoId,
    overlays: previousData.generatedOverlays,
    branding: previousData.branding,
    processingService: previousData.processingService,
    estimatedDuration: previousData.estimatedDuration,
    pollCount: 0,
    maxPolls: 60
  }
};

const statusResponse = $input.first().json;
const previousData = $('Extract Video ID').first().json;

const status = statusResponse.data?.status;
const videoUrl = statusResponse.data?.video_url;
const duration = statusResponse.data?.duration || previousData.estimatedDuration;
const pollCount = previousData.pollCount + 1;

return {
  json: {
    ...previousData,
    pollCount,
    status,
    videoUrl,
    actualDuration: duration,
    isComplete: status === 'completed',
    shouldContinuePolling: status === 'processing' && pollCount < previousData.maxPolls
  }
};

// Build Cloudinary transformation for smart overlays
const input = $input.first().json;
const cloudName = $env.CLOUDINARY_CLOUD_NAME;
const overlays = input.overlays || [];

let transformations = [];

for (const overlay of overlays) {
  if (overlay.type === 'text' || overlay.type === 'lowerThird') {
    const text = encodeURIComponent(overlay.text || 'Text');
    const fontSize = overlay.fontSize || 42;
    const fontFamily = overlay.fontFamily || 'Montserrat';
    const color = (overlay.color || '#ffffff').replace('#', '');

    // Map position names
    const positionMap = {
      'north': 'north',
      'south': 'south',
      'east': 'east',
      'west': 'west',
      'north_east': 'north_east',
      'north_west': 'north_west',
      'south_east': 'south_east',
      'south_west': 'south_west',
      'center': 'center'
    };
    const position = positionMap[overlay.position] || 'south';

    let transform = `l_text:${fontFamily}_${fontSize}:${text}`;
    transform += `,co_rgb:${color}`;
    transform += `,g_${position}`;
    if (overlay.xOffset) transform += `,x_${Math.abs(overlay.xOffset)}`;
    if (overlay.yOffset) transform += `,y_${Math.abs(overlay.yOffset)}`;

    // Add timing
    if (overlay.startTime !== undefined) {
      transform += `,so_${overlay.startTime}`;
    }
    if (overlay.endTime !== undefined) {
      transform += `,eo_${overlay.endTime}`;
    }

    transformations.push(transform);

  } else if (overlay.type === 'image') {
    if (overlay.src) {
      // For external images, we'd need to upload to Cloudinary first
      // For now, use fetch URL transformation
      const imageUrl = encodeURIComponent(overlay.src);
      const width = overlay.width || 150;
      const opacity = overlay.opacity || 100;
      const position = overlay.position || 'north_east';

      let transform = `l_fetch:${imageUrl}`;
      transform += `,w_${width}`;
      transform += `,o_${opacity}`;
      transform += `,g_${position}`;
      if (overlay.xOffset) transform += `,x_${Math.abs(overlay.xOffset)}`;
      if (overlay.yOffset) transform += `,y_${Math.abs(overlay.yOffset)}`;

      transformations.push(transform);
    }
  }
}

const transformationString = transformations.join('/');

return {
  json: {
    videoId: input.videoId,
    originalVideoUrl: input.videoUrl,
    overlays: input.overlays,
    transformationString,
    cloudName
  }
};

// Build Shotstack edit for smart overlays
const input = $input.first().json;
const overlays = input.overlays || [];
const videoDuration = input.actualDuration || 30;

const overlayClips = [];

for (const overlay of overlays) {
  const startTime = overlay.startTime || 0;
  const endTime = Math.min(overlay.endTime || videoDuration, videoDuration);
  const duration = endTime - startTime;

  if (overlay.type === 'text') {
    overlayClips.push({
      asset: {
        type: 'title',
        text: overlay.text,
        style: 'minimal',
        color: overlay.color || '#ffffff',
        size: overlay.fontSize > 48 ? 'large' : 'medium'
      },
      start: startTime,
      length: duration,
      position: overlay.position === 'south' ? 'bottom' : (overlay.position === 'west' ? 'left' : 'center'),
      offset: {
        x: (overlay.xOffset || 0) / 1000,
        y: -(overlay.yOffset || 0) / 1000
      },
      transition: overlay.animation === 'fadeIn' ? { in: 'fade', out: 'fade' } : null
    });

  } else if (overlay.type === 'lowerThird') {
    overlayClips.push({
      asset: {
        type: 'title',
        text: overlay.text,
        style: 'blockbuster',
        color: overlay.color || '#ffffff',
        size: 'small'
      },
      start: startTime,
      length: duration,
      position: 'bottomLeft',
      offset: { x: 0.05, y: -0.1 },
      transition: { in: 'slideLeft', out: 'slideLeft' }
    });

  } else if (overlay.type === 'image' && overlay.src) {
    overlayClips.push({
      asset: {
        type: 'image',
        src: overlay.src
      },
      start: startTime,
      length: duration,
      fit: 'none',
      scale: (overlay.width || 150) / 1920,
      position: overlay.position === 'north_east' ? 'topRight' : 'topLeft',
      offset: {
        x: -(overlay.xOffset || 30) / 1000,
        y: (overlay.yOffset || 30) / 1000
      },
      opacity: (overlay.opacity || 100) / 100
    });
  }
}

const editPayload = {
  timeline: {
    background: '#000000',
    tracks: [
      { clips: overlayClips },
      {
        clips: [{
          asset: { type: 'video', src: input.videoUrl },
          start: 0,
          length: videoDuration
        }]
      }
    ]
  },
  output: {
    format: 'mp4',
    resolution: 'hd'
  }
};

const shotstackStage = $env.SHOTSTACK_STAGE || 'sandbox';
const baseUrl = shotstackStage === 'v1' 
  ? 'https://api.shotstack.io/v1'
  : 'https://api.shotstack.io/stage';

return {
  json: {
    videoId: input.videoId,
    originalVideoUrl: input.videoUrl,
    overlays: input.overlays,
    editPayload,
    shotstackBaseUrl: baseUrl
  }
};

const cloudinaryResponse = $input.first().json;
const previousData = $('Build Cloudinary Transform').first().json;

let finalVideoUrl = cloudinaryResponse.secure_url;
if (cloudinaryResponse.eager && cloudinaryResponse.eager.length > 0) {
  finalVideoUrl = cloudinaryResponse.eager[0].secure_url;
}

return {
  json: {
    success: true,
    videoId: previousData.videoId,
    originalVideoUrl: previousData.originalVideoUrl,
    processedVideoUrl: finalVideoUrl,
    overlaysApplied: previousData.overlays.length,
    processingEngine: 'cloudinary'
  }
};

const response = $input.first().json;
const previousData = $('Build Shotstack Edit').first().json;

if (!response.success || !response.response?.id) {
  throw new Error('Shotstack submission failed');
}

// For simplicity, we'll return the render ID
// In production, you'd poll for completion
return {
  json: {
    success: true,
    videoId: previousData.videoId,
    originalVideoUrl: previousData.originalVideoUrl,
    shotstackRenderId: response.response.id,
    overlaysApplied: previousData.overlays.length,
    processingEngine: 'shotstack',
    message: 'Video submitted for processing. Poll the render endpoint for completion.'
  }
};

const input = $input.first().json;

return {
  json: {
    success: true,
    videoId: input.videoId,
    videoUrl: input.videoUrl,
    overlaysApplied: 0,
    message: 'No overlays were generated for this content'
  }
};

return {
  json: {
    success: false,
    error: 'Video generation failed or timed out',
    details: $json
  }
};
